class Solution:
    def maximumSumQueries(self, nums1, nums2, queries):
        n = len(nums1)
        ans = []
        for x, y in queries:
            best = -1
            for j in range(n):
                if nums1[j] >= x and nums2[j] >= y:
                    s = nums1[j] + nums2[j]
                    if s > best:
                        best = s
            ans.append(best)
        return ans

