class Solution:
    def maximumSumQueries(self, nums1, nums2, queries):
        n = len(nums1)
        pairs = sorted(zip(nums1, nums2), key=lambda p: -p[0])
        order = sorted(range(len(queries)), key=lambda i: -queries[i][0])
        ans = [-1] * len(queries)
        stack = []  # (b, sum) with b increasing and sum increasing bottom to top
        j = 0
        for qi in order:
            x, y = queries[qi]
            while j < n and pairs[j][0] >= x:
                b = pairs[j][1]
                s = pairs[j][0] + pairs[j][1]
                while stack and stack[-1][1] <= s:
                    stack.pop()
                if not stack or stack[-1][0] < b:
                    stack.append((b, s))
                j += 1
            lo, hi, best = 0, len(stack) - 1, -1
            while lo <= hi:
                mid = (lo + hi) // 2
                if stack[mid][0] >= y:
                    best = stack[mid][1]
                    hi = mid - 1
                else:
                    lo = mid + 1
            ans[qi] = best
        return ans

