var maximumSumQueries = function(nums1, nums2, queries) {
    const n = nums1.length;
    const pairs = nums1.map((v, i) => [v, nums2[i]]).sort((a, b) => b[0] - a[0]);
    const order = queries.map((_, i) => i).sort((a, b) => queries[b][0] - queries[a][0]);
    const ans = new Array(queries.length).fill(-1);
    const stack = []; // [b, sum] with b increasing and sum increasing bottom to top
    let j = 0;
    for (const qi of order) {
        const x = queries[qi][0], y = queries[qi][1];
        while (j < n && pairs[j][0] >= x) {
            const b = pairs[j][1];
            const s = pairs[j][0] + pairs[j][1];
            while (stack.length && stack[stack.length - 1][1] <= s) stack.pop();
            if (!stack.length || stack[stack.length - 1][0] < b) stack.push([b, s]);
            j++;
        }
        let lo = 0, hi = stack.length - 1, best = -1;
        while (lo <= hi) {
            const mid = (lo + hi) >> 1;
            if (stack[mid][0] >= y) {
                best = stack[mid][1];
                hi = mid - 1;
            } else {
                lo = mid + 1;
            }
        }
        ans[qi] = best;
    }
    return ans;
};
